function imgExst = fImageListV01(diag,scanNDir,nmbSht) %% function image exist % returns a array of logic for image exist% % imgExst = fImageListV01(diag,scanNDir,nmbSht)%% diag: name for diagnostic% scanNDir: scan# dir% nmbSht: # of shots in the scan%% imgExst: logic of image exist%%% Written by Kei Nakamura% 2014/4/1 ver.1: Created%%% main bodyimgExst = zeros(nmbSht,1);        % array for shot existfName = ['Scan*_' diag '_*.png'];    % file nameimgLst = dir([scanNDir filesep diag filesep fName]);         % image list[nmbImg,~] = size(imgLst);   % number of imagesprtNam = imgLst(1).name;prtNam = prtNam(1:8);   % partial nameif nmbImg == nmbSht    imgExst(:) = imgExst + 1;else    for jj=1:nmbSht        shotS = fGet3NmbStringV01(jj);  % shot string        fName = [prtNam diag '_' shotS '.png']; % filename        if exist([scanNDir filesep diag filesep fName],'file')            imgExst(jj) = 1;        end    endend
